#!/usr/bin/env python3
"""Modern climate data analysis script for Python 3."""

from __future__ import annotations

import configparser
from pathlib import Path

import pandas as pd


BASE_DIR = Path(__file__).resolve().parent
DEFAULT_DATA_PATH = BASE_DIR / "climate_analyzer" / "sample_data" / "climate_data.csv"
DEFAULT_CONFIG_PATH = BASE_DIR / "climate_analyzer" / "config.ini"


def read_config(config_path: Path = DEFAULT_CONFIG_PATH) -> configparser.ConfigParser:
    """Read the legacy configuration with modern configparser."""
    config = configparser.ConfigParser()
    config.read(config_path, encoding="utf-8")
    return config


def load_temperature_data(data_path: Path = DEFAULT_DATA_PATH) -> pd.DataFrame:
    """Load climate observations from CSV using UTF-8 encoding."""
    return pd.read_csv(data_path, encoding="utf-8", parse_dates=["date"])


def mean_temperatures_by_station(data: pd.DataFrame) -> pd.Series:
    """Return mean temperature per station, ordered by station id."""
    return data.groupby("station_id", sort=True)["temperature"].mean()


def main() -> None:
    read_config()
    data = load_temperature_data()

    for station_id, mean_temperature in mean_temperatures_by_station(data).items():
        print(f"Station {station_id} mean temperature: {mean_temperature:.1f}°C")


if __name__ == "__main__":
    main()
